+  /** Clears all dynamic ids so this reader can be reused for a new deserialization stream. */
+  public void reset() {
+    int dynamicReadId = dynamicReadStringId;
+    if (dynamicReadId != 0) {
+      for (int i = 0; i < dynamicReadId; i++) {
+        dynamicReadStringIds[i] = null;
+      }
+      dynamicReadStringId = 0;
+    }
+  }
+}

